return $input.all().map(item => {
  let url = item.json.Web || '';
  if (!url || typeof url !== 'string' || url.trim() === '') {
    return { json: { error: 'URL no valida', cleanUrl: '', originalUrl: url, telefono: item.json.telefono || '', web: item.json.Web || '' } };
  }
  url = url.trim();
  if (!url.match(/^https?:\/\//i)) { url = 'https://' + url; }
  url = url.replace(/^http:\/\//i, 'https://');
  url = url.replace(/^(https:\/\/)www\./i, '$1');
  if (!url.endsWith('/')) { url += '/'; }
  return { json: { cleanUrl: url, originalUrl: item.json.Web, telefono: item.json.telefono || '', web: item.json.Web || '' } };
});

return $input.all().map(item => {
  let html = item.json.htmlContent || '';
  if (!html || html.trim() === '') {
    return { json: { cleanText: '', web: item.json.web || '', telefono: item.json.telefono || '', error: 'Sin HTML' } };
  }
  const cleanText = html
    .replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?>[\s\S]*?<\/style>/gi, '')
    .replace(/<\/?[^>]+(>|$)/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 4000);
  return { json: { cleanText, web: item.json.web || '', telefono: item.json.telefono || '' } };
});

