return $input.all().map((item, i) => {
  const c = item.json.message?.content || {};
  const msg = c.mensaje || item.json.mensaje || '';
  const src = $('Limpiar HTML').all()[i].json;
  let pais = c.pais || '';
  let phone = String(c.telefono_whatsapp || '').replace(/\D/g, '');
  // Fallback: si la IA no determino pais/telefono, asumir Ecuador (593)
  if (phone.length < 10 || phone.length > 15) {
    let local = String(src.telefono || '').replace(/\D/g, '');
    if (local.startsWith('0')) local = local.slice(1);
    phone = local ? '593' + local : '';
    if (phone) pais = 'Ecuador (asumido)';
  }
  const linkWA = phone ? 'https://wa.me/' + phone + '?text=' + encodeURIComponent(msg) : 'REVISAR - sin telefono';
  return { json: {
    mensajeWA: msg,
    linkWA,
    pais: pais,
    telefonoIntl: phone,
    web: src.web || '',
    telefono: src.telefono || ''
  } };
});
